+func TestMergeStringListPreferFirst(t *testing.T) {
+	tests := []struct {
+		name      string
+		primary   []string
+		secondary []string
+		expected  []string
+	}{
+		{
+			name:      "empty both",
+			primary:   nil,
+			secondary: nil,
+			expected:  nil,
+		},
+		{
+			name:      "primary only",
+			primary:   []string{"a", "b"},
+			secondary: nil,
+			expected:  []string{"a", "b"},
+		},
+		{
+			name:      "secondary only",
+			primary:   nil,
+			secondary: []string{"x", "y"},
+			expected:  []string{"x", "y"},
+		},
+		{
+			name:      "primary takes precedence on duplicates",
+			primary:   []string{"a", "b"},
+			secondary: []string{"b", "c"},
+			expected:  []string{"a", "b", "c"},
+		},
+		{
+			name:      "trims whitespace",
+			primary:   []string{" a ", "  b"},
+			secondary: []string{"c  "},
+			expected:  []string{"a", "b", "c"},
+		},
+		{
+			name:      "filters empty strings",
+			primary:   []string{"a", "", "b"},
+			secondary: []string{"", "c"},
+			expected:  []string{"a", "b", "c"},
+		},
+	}
+
+	for _, tt := range tests {
+		t.Run(tt.name, func(t *testing.T) {
+			result := mergeStringListPreferFirst(tt.primary, tt.secondary)
+			if tt.expected == nil {
+				if result != nil {
+					t.Errorf("expected nil, got=%v", result)
+				}
+				return
+			}
+			if len(result) != len(tt.expected) {
+				t.Errorf("expected len=%d, got=%d", len(tt.expected), len(result))
+				return
+			}
+			for i := range tt.expected {
+				if result[i] != tt.expected[i] {
+					t.Errorf("at index %d: expected=%s, got=%s", i, tt.expected[i], result[i])
+				}
+			}
+		})
+	}
+}
